import { css, cx, keyframes } from '@emotion/css'
import { useReactiveRef } from '@guanghechen/react-hooks'
import { GomokuActionType } from '@kyokuya/react-game-gomoku-core'
import React from 'react'
import { GomokuGameContextType } from '../context/context'
import { Gomoku } from '../core/Gomoku'
import { useCurrentPlayer } from '../hook/useCurrentPlayer'

export interface IGomokuBoardProps {
  /**
   * Gomoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * CSS class name.
   */
  className?: string
}

export const GameBoard: React.FC<IGomokuBoardProps> = props => {
  const { overlay, className } = props
  const { state, dispatch } = React.useContext(GomokuGameContextType)
  const { GOMOKU_SIZE, gameStatus, players, pieces } = state

  const currentPlayerRef = useReactiveRef(useCurrentPlayer())
  const gomoku = React.useMemo(
    () =>
      new Gomoku({
        canvas: null,
        lines: GOMOKU_SIZE,
        pieces: [],
        pieceDrawers: [],
        onClick(r: number, c: number) {
          if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
            dispatch({ type: GomokuActionType.ACTIVE, payload: { r, c } })
            const currentPlayer = currentPlayerRef.current
            currentPlayer.onClickedCellChanged(r, c)
            currentPlayer.move()
          }
        },
      }),
    [GOMOKU_SIZE, currentPlayerRef, dispatch],
  )

  const canvasRef = React.useRef<HTMLCanvasElement>(null)
  React.useEffect(() => {
    gomoku.reset(canvasRef.current, players)
    return (): void => {
      gomoku.destroy()
    }
  }, [gomoku, players])

  const { r = -1, c = -1 } = state.activatedCell ?? {}
  React.useEffect(() => {
    gomoku.updateActivateCell(r, c)
    gomoku.draw(pieces)
  }, [gomoku, pieces, r, c])

  const classes = useStyles()
  return (
    <div className={cx(classes.container, className)}>
      <div key="overlay" className={classes.overlay} data-status={gameStatus}>
        {overlay}
      </div>
      <canvas ref={canvasRef} />
    </div>
  )
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => ({
  container: css`
    position: relative;
    box-sizing: content-box;
    display: inline-block;
    width: 100%;
    height: 100%;
    padding: 0;
    border: 0;
    margin: 0;
    font-family: Consolas, 'Source Code Pro', 'Roboto Mono', monospace, sans-serif;
  `,
  overlay: css`
    z-index: 2;
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    display: none;
    width: 100%;
    height: 100%;
    overflow: hidden;
    background: linear-gradient(
      45deg,
      hsl(30deg 20% 90% / 0.2),
      hsl(210deg 20% 100% / 0.3)
    );

    &[data-status="pending"] {
      display: block;
      backdrop-filter: blur(1px);
    }
    &[data-status="running"] {
      display: none;
    }
    &[data-status="paused"] {
      display: block;
      backdrop-filter: blur(16px);
    }
    &[data-status="finished"] {
      display: block;
      backdrop-filter: blur(4px);
      color: #ff00ff;
      animation: 1s 0s ${animations.finished} ease-in-out;
    }
  `,
})

const animations = {
  finished: keyframes`
    0% {
      transform: translate(0, -100px);
    }
    80% {
      transform: translate(0, 20px);
    }
    90% {
      transform: translate(0, -10px);
    }
    95% {
      transform: translate(0, 2px);
    }
    100% {
      transform: translate(0, 0);
    }
  `,
}
