import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { gomokuDirections, leftHalfGomokuDirectionTypes } from '@algorithm.ts/gomoku'

/**
 * Check if the game completed.
 *
 * @param pieces
 * @param MAX_ROW
 * @param MAX_COL
 * @param MAX_ADJACENT
 * @returns
 */
export function checkWinner(
  pieces: ReadonlyArray<IGomokuPiece>,
  MAX_ROW: number,
  MAX_COL: number,
  MAX_ADJACENT = 5,
): number | -1 {
  const board = new Int32Array(MAX_ROW * MAX_COL).fill(-1)
  for (const { r, c, p } of pieces) board[r * MAX_ROW + c] = p

  const idx = (r: number, c: number): number => r * MAX_ROW + c
  const isValidPos = (r: number, c: number): boolean =>
    r >= 0 && r < MAX_ROW && c >= 0 && c < MAX_COL

  for (const dirType of leftHalfGomokuDirectionTypes) {
    const [dr, dc] = gomokuDirections[dirType]
    for (let r = 0; r < MAX_ROW; ++r) {
      for (let c = 0; c < MAX_COL; ++c) {
        const playerId: number = board[idx(r, c)]
        if (playerId < 0) continue
        let cnt = 1
        for (let r2 = r + dr, c2 = c + dc; isValidPos(r2, c2); r2 += dr, c2 += dc) {
          if (board[idx(r2, c2)] !== playerId) break
          cnt += 1
        }
        if (cnt >= MAX_ADJACENT) return playerId
      }
    }
  }
  return -1
}
