import type { IGomokuState } from '@kyokuya/react-game-gomoku-core'
import { GomokuPlayerType, initGomokuState } from '@kyokuya/react-game-gomoku-core'
import { createPlayer } from '../core/player/createPlayer'
import type { IPlayer } from '../types'

export interface IGomokuGameState extends IGomokuState {
  /**
   * Total players.
   */
  players: IPlayer[]
}

export const initGomokuGameState = (initialState?: Partial<IGomokuGameState>): IGomokuGameState => {
  const baseState: IGomokuState = initGomokuState(initialState)
  const MAX_ROW: number = baseState.GOMOKU_SIZE
  const MAX_COL: number = baseState.GOMOKU_SIZE

  const players: IPlayer[] = (
    initialState?.players ?? [
      {
        type: GomokuPlayerType.HUMAN,
        name: 'wulala',
      },
      {
        type: GomokuPlayerType.COMPUTER,
        name: 'guanghechen',
      },
    ]
  ).map((player, playerId) =>
    createPlayer({ type: player.type, name: player.name }, playerId, MAX_ROW, MAX_COL),
  )

  return { ...baseState, players }
}
