import type React from 'react'

export type IMiddleware<P extends unknown[], R> = (next: (...args: P) => R) => (...args: P) => R
export type IContextMiddleware<State, Action> = IMiddleware<
  Parameters<React.Reducer<State, Action>>,
  ReturnType<React.Reducer<State, Action>>
>

export function composeMiddlewares<P extends unknown[], R>(
  ...middlewares: Array<IMiddleware<P, R>>
): IMiddleware<P, R> {
  if (middlewares.length === 1) return middlewares[0]
  return next => middlewares.reduceRight((prev, current) => current(prev), next)
}
