import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { GomokuInstructionType } from '../../constant'
import { checkWinner } from '../../util/status'
import type { IGomokuAction } from '../action'
import { GomokuActionType } from '../action'
import type { IGomokuContextMiddleware } from '../context'
import type { IGomokuState } from '../state'

export const actionReducer: IGomokuContextMiddleware =
  next =>
  (state: IGomokuState, action: IGomokuAction): IGomokuState => {
    switch (action.type) {
      case GomokuActionType.ACTIVE: {
        const { r, c } = action.payload
        if (state.activatedCell?.r === r && state.activatedCell?.c === c) return state
        return { ...state, activatedCell: { r, c } }
      }
      case GomokuActionType.MOVE: {
        const { r, c } = action.payload
        const { GOMOKU_SIZE } = state
        if (state.pieces.find(piece => piece.r === r && piece.c === c)) return state

        const previousPlayerId: number = state.currentPlayerId
        const currentPlayerId: number = (previousPlayerId + 1) % state.TOTAL_PLAYERS
        const piece: IGomokuPiece = { r, c, p: previousPlayerId }

        const nextPieces: IGomokuPiece[] = [...state.pieces, piece]
        const isCompleted: boolean = checkWinner(nextPieces, GOMOKU_SIZE, GOMOKU_SIZE) >= 0
        const isFinished = isCompleted || nextPieces.length === GOMOKU_SIZE * GOMOKU_SIZE

        return {
          ...state,
          gameStatus: isFinished ? GameRunningStatus.FINISHED : state.gameStatus,
          winner: isFinished && isCompleted ? previousPlayerId : -1,
          pieces: nextPieces,
          previousPlayerId,
          currentPlayerId,
          attemptTick: state.attemptTick + 1,
          instructions: [
            ...state.instructions,
            {
              type: GomokuInstructionType.MOVE,
              payload: piece,
              timestamp: new Date().toISOString(),
            },
          ],
        }
      }
      case GomokuActionType.RETRACT: {
        // Only worked in running state or finished state.
        if (
          state.gameStatus !== GameRunningStatus.RUNNING &&
          state.gameStatus !== GameRunningStatus.FINISHED
        )
          return state

        let idx = state.pieces.length - 1
        for (; idx >= 0; --idx) {
          if (state.pieces[idx].p === state.currentPlayerId) break
        }

        // Not enough pieces to retract.
        if (idx < 0) return state

        const steps: number = state.pieces.length - idx
        const pieces: IGomokuPiece[] = state.pieces.slice(0, state.pieces.length - steps)

        const previousPlayerId: number =
          pieces.length <= 0 ? -1 : (pieces.length - 1) % state.TOTAL_PLAYERS
        const currentPlayerId: number = (previousPlayerId + 1) % state.TOTAL_PLAYERS

        return {
          ...state,
          gameStatus: GameRunningStatus.RUNNING,
          pieces,
          previousPlayerId,
          currentPlayerId,
          attemptTick: state.attemptTick + 1,
          instructions: [
            ...state.instructions,
            {
              type: GomokuInstructionType.RETRACT,
              payload: steps,
              timestamp: new Date().toISOString(),
            },
          ],
        }
      }
      default:
        return next(state, action)
    }
  }
